import { useRef, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { Float, MeshTransmissionMaterial, Environment } from "@react-three/drei";
import * as THREE from "three";

/* ── Palette (matches cream/ink theme) ── */
const INK = "#1a1a1a";
const CREAM = "#f5f0e8";
const GOLD = "#c9a96e";
const WARM_GRAY = "#9c958e";

/* ── Central Agent Core: a glass-like icosahedron ── */
function AgentCore() {
  const ref = useRef<THREE.Mesh>(null!);

  useFrame((_, delta) => {
    ref.current.rotation.y += delta * 0.15;
    ref.current.rotation.x += delta * 0.08;
  });

  return (
    <Float speed={1.5} rotationIntensity={0.3} floatIntensity={0.6}>
      <mesh ref={ref} scale={1.6}>
        <icosahedronGeometry args={[1, 1]} />
        <MeshTransmissionMaterial
          backside
          thickness={0.5}
          chromaticAberration={0.3}
          anisotropy={0.2}
          distortion={0.4}
          distortionScale={0.5}
          temporalDistortion={0.2}
          color={CREAM}
          roughness={0.1}
          ior={1.5}
          transmission={0.95}
        />
      </mesh>
    </Float>
  );
}

/* ── Orbiting token ring ── */
function OrbitingToken({
  radius,
  speed,
  offset,
  size,
  color,
}: {
  radius: number;
  speed: number;
  offset: number;
  size: number;
  color: string;
}) {
  const ref = useRef<THREE.Mesh>(null!);

  useFrame(({ clock }) => {
    const t = clock.getElapsedTime() * speed + offset;
    ref.current.position.x = Math.cos(t) * radius;
    ref.current.position.z = Math.sin(t) * radius;
    ref.current.position.y = Math.sin(t * 2) * 0.3;
    ref.current.rotation.x += 0.02;
    ref.current.rotation.y += 0.03;
  });

  return (
    <mesh ref={ref}>
      <octahedronGeometry args={[size, 0]} />
      <meshStandardMaterial
        color={color}
        metalness={0.8}
        roughness={0.2}
      />
    </mesh>
  );
}

/* ── Floating particles ── */
function Particles({ count = 60 }) {
  const ref = useRef<THREE.Points>(null!);

  const positions = useMemo(() => {
    const pos = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 2 + Math.random() * 2.5;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, [count]);

  useFrame((_, delta) => {
    ref.current.rotation.y += delta * 0.05;
    ref.current.rotation.x += delta * 0.02;
  });

  return (
    <points ref={ref}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          args={[positions, 3]}
        />
      </bufferGeometry>
      <pointsMaterial
        color={WARM_GRAY}
        size={0.04}
        sizeAttenuation
        transparent
        opacity={0.7}
      />
    </points>
  );
}

/* ── Wireframe ring ── */
function WireRing() {
  const ref = useRef<THREE.Mesh>(null!);

  useFrame(({ clock }) => {
    ref.current.rotation.x = Math.PI / 2 + Math.sin(clock.getElapsedTime() * 0.3) * 0.15;
    ref.current.rotation.z = clock.getElapsedTime() * 0.1;
  });

  return (
    <mesh ref={ref}>
      <torusGeometry args={[2.2, 0.015, 16, 100]} />
      <meshStandardMaterial color={INK} metalness={0.5} roughness={0.3} />
    </mesh>
  );
}

/* ── Second wireframe ring at angle ── */
function WireRing2() {
  const ref = useRef<THREE.Mesh>(null!);

  useFrame(({ clock }) => {
    ref.current.rotation.x = Math.PI / 3 + Math.cos(clock.getElapsedTime() * 0.25) * 0.1;
    ref.current.rotation.y = clock.getElapsedTime() * 0.08;
  });

  return (
    <mesh ref={ref}>
      <torusGeometry args={[2.8, 0.01, 16, 100]} />
      <meshStandardMaterial
        color={WARM_GRAY}
        metalness={0.4}
        roughness={0.4}
        transparent
        opacity={0.5}
      />
    </mesh>
  );
}

/* ── Main exported scene ── */
export function HeroScene() {
  return (
    <div className="h-[400px] w-[320px] md:h-[500px] md:w-[400px] lg:h-[540px] lg:w-[460px]">
      <Canvas
        camera={{ position: [0, 0, 6], fov: 45 }}
        gl={{ antialias: true, alpha: true }}
        style={{ background: "transparent" }}
      >
        <ambientLight intensity={0.4} />
        <directionalLight position={[5, 5, 5]} intensity={1.2} color={CREAM} />
        <directionalLight position={[-3, -2, 4]} intensity={0.4} color={GOLD} />
        <pointLight position={[0, 3, 0]} intensity={0.6} color={GOLD} />

        <AgentCore />

        {/* Orbiting tokens */}
        <OrbitingToken radius={2.5} speed={0.6} offset={0} size={0.15} color={GOLD} />
        <OrbitingToken radius={2.5} speed={0.6} offset={Math.PI * 0.66} size={0.12} color={INK} />
        <OrbitingToken radius={2.5} speed={0.6} offset={Math.PI * 1.33} size={0.13} color={WARM_GRAY} />

        {/* Inner orbit */}
        <OrbitingToken radius={1.8} speed={-0.8} offset={0.5} size={0.1} color={GOLD} />
        <OrbitingToken radius={1.8} speed={-0.8} offset={Math.PI + 0.5} size={0.1} color={INK} />

        <WireRing />
        <WireRing2 />
        <Particles />

        <Environment preset="city" environmentIntensity={0.3} />
      </Canvas>
    </div>
  );
}
