import { useRef } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { Float, RoundedBox, Html } from "@react-three/drei";
import * as THREE from "three";

/* ── Palette ── */
const BEIGE = "#e8e0d4";
const BEIGE_LIGHT = "#f0eae0";
const BEIGE_DARK = "#d4cdc4";
const INK = "#1a1a1a";
const SCREEN_BG = "#2a2a2a";
const GOLD = "#c9a96e";

/* ── CRT Screen content rendered as HTML ── */
function ScreenContent() {
  return (
    <Html
      transform
      distanceFactor={1.5}
      position={[0, 0.35, 0.52]}
      style={{
        width: "280px",
        height: "210px",
        background: "#1e1e1e",
        borderRadius: "4px",
        overflow: "hidden",
        fontFamily: "'Geist Mono', 'Monaco', monospace",
        fontSize: "11px",
        color: "#e0ddd6",
        userSelect: "none",
        pointerEvents: "none",
      }}
    >
      <div style={{ padding: "10px 12px", height: "100%" }}>
        {/* Title bar */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "8px",
            opacity: 0.5,
            fontSize: "10px",
            letterSpacing: "0.05em",
          }}
        >
          <span>YieldOS 1.0</span>
          <span style={{ fontFamily: "monospace" }}>■ ■ ■</span>
        </div>

        {/* Sidebar + Content */}
        <div style={{ display: "flex", gap: "12px", height: "calc(100% - 28px)" }}>
          {/* Sidebar */}
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              gap: "5px",
              fontSize: "10px",
              minWidth: "70px",
            }}
          >
            {[
              { icon: "◆", label: "System", color: "#6b9bd2" },
              { icon: "◆", label: "Wallet", color: "#c9a96e" },
              { icon: "◆", label: "Staking", color: "#7aba7a" },
              { icon: "◆", label: "Agent", color: "#e0ddd6" },
              { icon: "◆", label: "Logs", color: "#9c958e" },
            ].map((item) => (
              <div
                key={item.label}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "5px",
                }}
              >
                <span style={{ color: item.color, fontSize: "6px" }}>{item.icon}</span>
                <span>{item.label}</span>
              </div>
            ))}
          </div>

          {/* Main content window */}
          <div
            style={{
              flex: 1,
              background: "#f0eae0",
              color: "#1a1a1a",
              borderRadius: "2px",
              padding: "8px",
              fontSize: "10px",
              lineHeight: "1.5",
              fontFamily: "'Geist Mono', 'Monaco', monospace",
            }}
          >
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                borderBottom: "1px dashed #9c958e",
                paddingBottom: "4px",
                marginBottom: "6px",
                fontSize: "9px",
                fontWeight: "bold",
              }}
            >
              <span>agent.log</span>
              <span>[x]</span>
            </div>
            <div style={{ opacity: 0.85 }}>
              <span style={{ color: "#6b9bd2" }}>{'>'}</span> Yield accrued: 0.003 stETH
              <br />
              <span style={{ color: "#7aba7a" }}>{'>'}</span> Swapped → 5.12 USDC
              <br />
              <span style={{ color: "#c9a96e" }}>{'>'}</span> Inference paid. Thinking...
              <br />
              <span style={{ color: "#e0ddd6" }}>{'>'}</span> Task complete.
              <br />
              <span style={{ color: "#9c958e" }}>{'>'}</span> Ready when you are.
              <br />
              <span
                style={{
                  display: "inline-block",
                  width: "6px",
                  height: "11px",
                  background: "#c9a96e",
                  animation: "blink 1s step-end infinite",
                  verticalAlign: "text-bottom",
                  marginLeft: "2px",
                }}
              />
            </div>
          </div>
        </div>
      </div>
      <style>{`@keyframes blink { 50% { opacity: 0; } }`}</style>
    </Html>
  );
}

/* ── Keyboard keys ── */
function Keyboard() {
  const rows = [13, 12, 12, 11, 8];
  const keyWidth = 0.14;
  const keyGap = 0.02;
  const keyHeight = 0.04;
  const keyDepth = 0.12;

  return (
    <group position={[0, -1.55, 1.15]} rotation={[-0.12, 0, 0]}>
      {/* Keyboard base */}
      <RoundedBox args={[2.6, 0.08, 0.9]} radius={0.03} smoothness={4} position={[0, -0.02, 0]}>
        <meshStandardMaterial color={BEIGE_LIGHT} metalness={0.1} roughness={0.6} />
      </RoundedBox>
      {/* Key rows */}
      {rows.map((keysInRow, rowIdx) => {
        const rowWidth = keysInRow * (keyWidth + keyGap) - keyGap;
        const startX = -rowWidth / 2 + keyWidth / 2;
        const z = -0.3 + rowIdx * (keyDepth + 0.02);
        return Array.from({ length: keysInRow }, (_, colIdx) => (
          <RoundedBox
            key={`${rowIdx}-${colIdx}`}
            args={[
              rowIdx === 4 && colIdx === 4 ? keyWidth * 3 + keyGap * 2 : keyWidth,
              keyHeight,
              keyDepth,
            ]}
            radius={0.015}
            smoothness={2}
            position={[startX + colIdx * (keyWidth + keyGap), 0.04, z]}
          >
            <meshStandardMaterial color={BEIGE_DARK} metalness={0.05} roughness={0.7} />
          </RoundedBox>
        ));
      })}
    </group>
  );
}

/* ── Sticker ── */
function Sticker({
  position,
  color,
  label,
}: {
  position: [number, number, number];
  color: string;
  label: string;
}) {
  return (
    <group position={position}>
      <RoundedBox args={[0.45, 0.2, 0.02]} radius={0.03} smoothness={4}>
        <meshStandardMaterial color={color} metalness={0.1} roughness={0.8} />
      </RoundedBox>
      <Html
        transform
        distanceFactor={1.5}
        position={[0, 0, 0.015]}
        style={{
          fontSize: "7px",
          fontFamily: "'Geist Mono', monospace",
          color: "#fff",
          fontWeight: "bold",
          letterSpacing: "0.08em",
          textTransform: "uppercase",
          whiteSpace: "nowrap",
          userSelect: "none",
          pointerEvents: "none",
        }}
      >
        {label}
      </Html>
    </group>
  );
}

/* ── Logo grid (like the Unisys/IBM grid pattern) ── */
function LogoGrid() {
  return (
    <group position={[0.75, -1.0, 0.47]}>
      {Array.from({ length: 9 }, (_, i) => (
        <mesh key={i} position={[(i % 3) * 0.08, -Math.floor(i / 3) * 0.08, 0]}>
          <boxGeometry args={[0.05, 0.05, 0.02]} />
          <meshStandardMaterial color={INK} metalness={0.3} roughness={0.5} />
        </mesh>
      ))}
    </group>
  );
}

/* ── Floppy disk slot ── */
function FloppySlot() {
  return (
    <group position={[0, -0.55, 0.47]}>
      <mesh>
        <boxGeometry args={[0.7, 0.06, 0.01]} />
        <meshStandardMaterial color="#3a3a3a" metalness={0.4} roughness={0.5} />
      </mesh>
    </group>
  );
}

/* ── The full retro computer ── */
function RetroComputer() {
  const groupRef = useRef<THREE.Group>(null!);

  useFrame(({ pointer }) => {
    // Subtle mouse follow
    groupRef.current.rotation.y = THREE.MathUtils.lerp(
      groupRef.current.rotation.y,
      pointer.x * 0.08,
      0.05
    );
    groupRef.current.rotation.x = THREE.MathUtils.lerp(
      groupRef.current.rotation.x,
      pointer.y * 0.04,
      0.05
    );
  });

  return (
    <Float speed={1.0} rotationIntensity={0.05} floatIntensity={0.3}>
      <group ref={groupRef} rotation={[0.05, -0.15, 0]} position={[0, 0.3, 0]}>
        {/* ── Monitor body ── */}
        <RoundedBox args={[2.3, 2.6, 0.9]} radius={0.1} smoothness={4} position={[0, 0, 0]}>
          <meshStandardMaterial color={BEIGE_LIGHT} metalness={0.08} roughness={0.65} />
        </RoundedBox>

        {/* ── Screen bezel (recessed) ── */}
        <RoundedBox args={[1.9, 1.6, 0.1]} radius={0.12} smoothness={4} position={[0, 0.35, 0.42]}>
          <meshStandardMaterial color={BEIGE_DARK} metalness={0.1} roughness={0.5} />
        </RoundedBox>

        {/* ── CRT screen (dark inset) ── */}
        <RoundedBox args={[1.7, 1.4, 0.08]} radius={0.15} smoothness={4} position={[0, 0.35, 0.47]}>
          <meshStandardMaterial color={SCREEN_BG} metalness={0.3} roughness={0.4} />
        </RoundedBox>

        {/* ── Screen content ── */}
        <ScreenContent />

        {/* ── Floppy slot below screen ── */}
        <FloppySlot />

        {/* ── Logo grid bottom right ── */}
        <LogoGrid />

        {/* ── Stickers ── */}
        <Sticker position={[-0.7, -0.85, 0.47]} color="#8B2020" label="YIELD AGENT" />

        {/* ── Keyboard ── */}
        <Keyboard />
      </group>
    </Float>
  );
}

/* ── Main exported scene ── */
export function HeroScene() {
  return (
    <div className="h-[420px] w-[320px] md:h-[520px] md:w-[420px] lg:h-[580px] lg:w-[480px]">
      <Canvas
        camera={{ position: [0, 0, 6], fov: 40 }}
        gl={{ antialias: true, alpha: true }}
        style={{ background: "transparent" }}
      >
        <ambientLight intensity={0.8} />
        <directionalLight position={[3, 4, 5]} intensity={0.8} />
        <directionalLight position={[-2, 1, 3]} intensity={0.3} color={GOLD} />

        <RetroComputer />
      </Canvas>
    </div>
  );
}
